  // refrigerants
  fluid:           { label: 'Маркировка' },
  package:         { label: 'Упаковка' },
  net_weight_kg:   { label: 'Нетто',             unit: 'кг' },
  // materials
  diameter_mm:     { label: 'Диаметр',           unit: 'мм' },
