  power_kw:        { label: 'Мощность',          unit: 'кВт' },
  current_a:       { label: 'Ток',               unit: 'А' },
  rpm:             { label: 'Обороты вентилятора', unit: 'об/мин' },
  pipe_d_in:       { label: 'Вход (труба)' },
  pipe_d_out:      { label: 'Выход (труба)' },
