// Хелпер для форматирования чисел (например количества)
function formatNumberShort(n) {
  if (n === null || n === undefined) return '0';
  const v = Number(n);
  if (!isFinite(v)) return '0';
  if (v % 1 === 0) return String(v);
  return v.toFixed(2).replace(/\.?0+$/, '');
}

