    openQrModal({
      title: 'QR-код · Договор ' + (number || '#' + contractId),
      subtitle: contractorName || '',
      url: url,
      type: 'contract',
      password: pw,
      contractId: contractId,
      data: {
        contractId: contractId,
        number: number,
        contractorName: contractorName,
        token: r.public_token,
      },
    });
